mapper.select:
SELECT dl.*, d.number as device_number
FROM device_locations dl
JOIN devices d ON dl.device_id = d.id
WHERE dl.device_id = #{deviceId}

    AND dl.timestamp >= #{fromTime}


    AND dl.timestamp <= #{toTime}

ORDER BY dl.timestamp DESC

    LIMIT #{limit}

mapper.delete:
DELETE FROM device_locations
WHERE device_id = #{deviceId}
AND timestamp < #{olderThan}

DELETE FROM geofences
WHERE id = #{id}
AND customer_id = #{customerId}

mapper.select:
SELECT *
FROM geofences
WHERE id = #{id}
AND customer_id = #{customerId}

SELECT * FROM geofences WHERE customer_id = #{customerId}
AND active = true
ORDER BY name

SELECT device_id
FROM geofence_devices
WHERE geofence_id = #{geofenceId}

mapper.update:
UPDATE geofence_devices
SET status = #{status},
    last_triggered_at = CURRENT_TIMESTAMP
WHERE geofence_id = #{geofenceId}
AND device_id = #{deviceId}
